from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a phrase
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language phrase for a single predicate."""
        # Strip surrounding quotes and whitespace
        obj = obj.strip().strip('"')
        # Normalise predicate for lookup
        p = pred.lower().replace(" ", "")
        # Helper to format ISO dates nicely
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        # Mapping of predicates to phrase templates
        if p == "birthdate":
            return f"{subj} was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"{subj} was born in {obj}"
        if p == "deathdate":
            return f"{subj} died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"{subj} died in {obj}"
        if p == "nationality":
            # Map country to demonym for a smoother phrase
            demonyms = {
                "United States": "American",
                "United Kingdom": "British",
                "Canada": "Canadian",
                "Russia": "Russian",
                "China": "Chinese",
                "France": "French",
                "Germany": "German",
                "Japan": "Japanese",
                "Italy": "Italian",
                "Australia": "Australian",
                "India": "Indian",
                # add more as needed
            }
            dem = demonyms.get(obj, obj)
            # Return phrase without repeating subject; will be combined later
            return f"The {dem}"
        if p == "dateofretirement":
            # Format date if possible
            try:
                from datetime import datetime
                dt = datetime.strptime(obj.strip().strip('"'), "%Y-%m-%d")
                date_str = dt.strftime("%B %-d, %Y")
            except Exception:
                date_str = obj
            return f"{subj} retired on {date_str}"
        if p == "occupation":
            return f"{subj} was a {obj}"
        if p == "status":
            # Use natural phrasing and lower‑case status values
            low = obj.lower()
            if low == "retired":
                return f"{subj} is retired"
            elif low == "active":
                return f"{subj} is active"
            else:
                return f"{subj} has status {obj}"
        if p == "selectedbynasa":
            return f"{subj} was selected by NASA in {obj}"
        if p == "mission":
            # Assume subject is an astronaut
            return f"{subj} was a crew member of {obj}"
        if p == "timeinspace":
            # Convert minutes to hours/minutes if possible
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"{subj} spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"{subj} spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"{subj} spent {obj} minutes in space"
        if p == "title":
            return f"{subj} held the title of {obj}"
        if p == "award":
            return f"{subj} received the {obj}"
        if p == "awards":
            return f"{subj} received {obj} awards"
        if p == "ribbonaward":
            return f"{subj} was awarded the {obj}"
        if p == "operator":
            # Prefer passive voice for readability
            # Add definite article if subject looks like a mission name
            article = "The " if not subj.lower().startswith(("the ", "a ")) else ""
            return f"{article}{subj} was operated by {obj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            return f"{subj}'s backup pilot was {obj}"
        if p == "crewmembers":
            return f"{obj} was a crew member of {subj}"
        if p == "alternativename":
            return f"{subj} is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"{subj} served as Chief of the Astronaut Office in {obj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "bird":
            return f"The {obj} is the state bird of {subj}"
        # Generic fallback
        return f"{subj} {pred} {obj}"

    # Build structures keyed by mission and astronaut
    from collections import defaultdict

    mission_to_astronauts = defaultdict(list)      # mission -> list of astronaut names
    astronaut_info = defaultdict(dict)            # astronaut -> predicate -> object
    mission_info = defaultdict(lambda: {"operator": None,
                                         "backupPilot": None,
                                         "commander": None,
                                         "crewMembers": []})  # mission -> extra info

    for t in triples:
        pred = t.predicate.lower()
        if pred == "mission":
            mission_to_astronauts[t.object].append(t.subject)
        elif pred in {"operator", "backuppilot", "commander"}:
            info = mission_info[t.subject]
            if pred == "operator":
                info["operator"] = t.object
            elif pred == "backuppilot":
                info["backupPilot"] = t.object
            elif pred == "commander":
                info["commander"] = t.object
        elif pred == "crewmembers":
            mission_info[t.subject]["crewMembers"].append(t.object)
        else:
            astronaut_info[t.subject][pred] = t.object

    sentences = []

    # Create sentences centered on missions (including astronauts)
    for mission, astronauts in mission_to_astronauts.items():
        # Join astronaut names nicely
        if len(astronauts) == 1:
            astro_part = astronauts[0]
        elif len(astronauts) == 2:
            astro_part = f"{astronauts[0]} and {astronauts[1]}"
        else:
            astro_part = ", ".join(astronauts[:-1]) + f", and {astronauts[-1]}"

        base = f"{astro_part} were crew members of {mission}"
        info = mission_info[mission]

        if info["operator"]:
            base += f", operated by {info['operator']}"
        if info["commander"]:
            base += f", commanded by {info['commander']}"
        if info["backupPilot"]:
            base += f", with {info['backupPilot']} as backup pilot"

        # Add any additional crew members not already listed as astronauts
        extra_crew = [c for c in info["crewMembers"] if c not in astronauts]
        if extra_crew:
            if len(extra_crew) == 1:
                crew_part = extra_crew[0]
            elif len(extra_crew) == 2:
                crew_part = f"{extra_crew[0]} and {extra_crew[1]}"
            else:
                crew_part = ", ".join(extra_crew[:-1]) + f", and {extra_crew[-1]}"
            base += f", and also includes crew member {crew_part}"

        sentences.append(base + ".")

    # Fallback: handle triples that were not part of any mission sentence
    covered = set()
    for mission, astronauts in mission_to_astronauts.items():
        covered.update(astronauts)
        covered.add(mission)
    remaining = [t for t in triples if t.subject not in covered and t.object not in covered]

    if remaining:
        # Group remaining triples by subject as before
        groups = defaultdict(list)
        for t in remaining:
            groups[t.subject].append(t)
        for subj, items in groups.items():
            parts = [phrase(subj, t.predicate, t.object) for t in items]
            if len(parts) == 1:
                sent = parts[0]
            else:
                sent = ", ".join(parts[:-1]) + ", and " + parts[-1]
            sentences.append(sent)

    return " ".join(sentences)

# EVOLVE-BLOCK-END
